FUNCTION calculate_potential_energy(mass, height, gravity):
 // mass in kg, height in meters, gravity in m/s²
 // Default gravity = 9.8 m/s² (Earth)
 IF height < 0:
 PRINT "Warning: Negative height, using absolute value"
 height = ABS(height)

 potential_energy = mass * gravity * height
 RETURN potential_energy // in Joules

// Example: 1000kg water in dam at 50m height
mass = 1000
height = 50
gravity = 9.8
pe = calculate_potential_energy(mass, height, gravity)
PRINT "Potential Energy:", pe, "Joules"

// This water falling can generate:
// At 90% efficiency: electrical = pe * 0.9
// = 490,000 * 0.9 = 441,000 J = 122.5 Wh
